CAPITALIZE_SHA = "18f1e1a2555d378a84f81059c9999b9160f2e004"

out = []
for db in DBS:
    for page_id, sample in db["pages"]:
        if sample == "responsive-wide":
            json_path = os.path.join(db["samples_dir"], "responsive.json")
            prefix = "_Note: same JSON as `responsive`, rendered at a wider viewport to trigger the >=768px breakpoint flip._\n\n"
        else:
            json_path = os.path.join(db["samples_dir"], f"{sample}.json")
            prefix = ""
        if not os.path.exists(json_path):
            print(f"MISSING: {json_path}", file=sys.stderr)
            continue
        with open(json_path) as f:
            obj = json.load(f)
        pretty = json.dumps(obj, indent=2)
        sha = CAPITALIZE_SHA if (db["prop"] == "textTransform" and sample == "capitalize") else db["sha"]
        img_url = f"https://raw.githubusercontent.com/j0yhq/flexbox-swift/{sha}/Tests/JoyDOMTests/PropertyCoverage/Typography/__Snapshots__/typography/{db['kebab']}/{sample}.png"
        content = f"![{sample}.png]({img_url})\n{prefix}```json\n{pretty}\n```"
        out.append({"page_id": page_id, "sample": sample, "prop": db["prop"], "new_str": content})

print(f"Total: {len(out)}", file=sys.stderr)
with open("/tmp/manifest.json","w") as f:
    json.dump(out, f)
